mapper.select:


SELECT /* getProfileStats */
       #{userNumb} AS USER_NUMB
     , ( SELECT COUNT(*)
           FROM TM_REPORT R
          WHERE R.USER_NUMB = #{userNumb}
            AND R.REPT_STAT = #{reportStatDone}
       ) AS TOTAL_READ_BOOK_CNT
     , ( SELECT COUNT(*)
           FROM TB_FOLLOW F
          WHERE F.USER_NUMB = #{userNumb}
       ) AS FOLLOWING_CNT
     , ( SELECT COUNT(*)
           FROM TB_FOLLOW F
          WHERE F.FLOW_NUMB = #{userNumb}
       ) AS FOLLOWER_CNT
     , ( SELECT COUNT(*)
           FROM TB_LIKEXX L
          WHERE L.TAGT_TYPE = #{likeTargetReport}
            AND EXISTS (
                SELECT 1
                  FROM TM_REPORT R
                 WHERE R.REPT_NUMB = L.TAGT_NUMB
                   AND R.USER_NUMB = #{userNumb}
            )
       ) AS RECEIVED_LIKE_CNT
  FROM DUAL
